(function ($) {
  'use strict';

  /**
   * Extraire les valeurs (id) des checkbox sélectionnés
   * @param {object} $inputs Liste des checkbox
   * @returns {array} Tableaux des valeurs
   */
  function getInputsCheckedByValue($inputs) {
    const checkedInputs = [];

    if ($inputs.length > 0) {
      $inputs.each(function () {
        if ($(this).is(":checked")) {
          checkedInputs.push($(this).val());
        }
      });
    }
    return checkedInputs;
  }

  /**
   * Filtrer les articles selon les checkbox sélectionnés par l'utilisateur
   * @use ajaxReload() fonction globale Spip de rechargement en ajax du bloc identifié dans le premier paramètre.
   */
  function filtrerArticles() {
    let $inputs = $(this).parents("form").find("input[type='checkbox']"),
      checkedInputs = getInputsCheckedByValue($inputs),
      ajaxParameters = { mots: [] };

    for (const id of checkedInputs) {
      ajaxParameters.mots.push(id);
    }

    ajaxReload("articles", {
      history: true,
      args: ajaxParameters,
    });
  }

  /**
   * Recharchement en ajax des articles en fonction des critères
   * de filtres choisis par l'utilisateur.
   */
  $(function () {
    // document is ready
    $(".formulaire_filtrer_articles").on(
      "click",
      "input[type='checkbox']",
      filtrerArticles,
    );
  });

})(jQuery);
